#include <stdio.h>
#include <stdlib.h>
#include <limits.h>
#define MAX_N 100005
#define INF INT_MAX
// Define the structure for a tree edge
typedef struct Edge {
    int to;
    int weight;
    struct Edge* next;
} Edge;
// Define the structure for a tree
typedef struct Tree {
    Edge** edges;
    int* maxGain;
    int n;
} Tree;
// Function to create a new edge
Edge* createEdge(int to, int weight) {
    Edge* edge = (Edge*) malloc(sizeof(Edge));
    edge->to = to;
    edge->weight = weight;
    edge->next = NULL;
    return edge;
}
// Function to create a new tree
Tree* createTree(int n) {
    Tree* tree = (Tree*) malloc(sizeof(Tree));
    tree->edges = (Edge**) malloc(n * sizeof(Edge*));
    tree->maxGain = (int*) malloc(n * sizeof(int));
    tree->n = n;
    for (int i = 0; i < n; i++) {
        tree->edges[i] = NULL;
        tree->maxGain[i] = -INF;
    }
    return tree;
}
// Function to add an edge to the tree
void addEdge(Tree* tree, int from, int to, int weight) {
    Edge* edge = createEdge(to, weight);
    edge->next = tree->edges[from];
    tree->edges[from] = edge;
}
// Function to perform DFS traversal and calculate maximum gain
void dfs(Tree* tree, int node, int parent) {
    int maxGain = -INF;
    for (Edge* edge = tree->edges[node]; edge != NULL; edge = edge->next) {
        if (edge->to != parent) {
            dfs(tree, edge->to, node);
            maxGain = max(maxGain, tree->maxGain[edge->to] + edge->weight);
        }
    }
    tree->maxGain[node] = maxGain;
}
// Function to calculate maximum gain for a query
int calculateMaxGain(Tree* tree, int from, int to) {
    int maxGain = -INF;
    for (Edge* edge = tree->edges[from]; edge != NULL; edge = edge->next) {
        if (edge->to == to) {
            maxGain = max(maxGain, edge->weight);
        } else {
            maxGain = max(maxGain, tree->maxGain[edge->to] + edge->weight);
        }
    }
    return maxGain;
}
int main() {
    int n, q;
    scanf("%d %d", &n, &q);
    Tree* tree = createTree(n);
    for (int i = 0; i < n - 1; i++) {
        int from, to, weight;
        scanf("%d %d %d", &from, &to, &weight);
        addEdge(tree, from - 1, to - 1, weight);
        addEdge(tree, to - 1, from - 1, weight);
    }
    dfs(tree, 0, -1);
    for (int i = 0; i < q; i++) {
        int from, to;
        scanf("%d %d", &from, &to);
        printf("%d\n", calculateMaxGain(tree, from - 1, to - 1));
    }
    return 0;
}

